export const 鎮宅飛尸 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：桿（左端垂圈尾）＋短桿＋左右圈柱
    線(p => p.M(X(1.2), Z(1.1)).L(X(6.9), Z(1.0)));
    圈(0.9, 1.1);
    圈(7.2, 1.0);
    線(p => p.M(X(0.9), Z(1.45)).L(X(0.9), Z(1.9)));
    圈(0.9, 2.25);
    線(p => p.M(X(2.7), Z(2.3)).L(X(3.9), Z(2.25)));
    圈(2.4, 2.3);
    圈(4.2, 2.25);
    for (const z of [3.2, 4.9, 6.5, 8.0])
        圈(0.6, z);
    for (const z of [3.3, 5.0, 6.6, 8.2])
        圈(7.3, z);
    // 天匣：頂桁＋乙折＋內田田對
    線(p => p.M(X(1.4), Z(3.3)).L(X(6.4), Z(3.2)), 0.42);
    線(p => p.M(X(1.4), Z(4.6)).L(X(4.1), Z(4.5)).L(X(1.5), Z(5.5)).L(X(4.0), Z(5.45)), 0.36);
    線(p => p.M(X(1.3), Z(4.55)).L(X(1.3), Z(8.3)));
    線(p => p.M(X(6.5), Z(4.5)).L(X(6.5), Z(8.25)));
    const 田 = (x0, z0, w, h) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z0 + h)).L(X(x0 + w), Z(z0 + h - 0.05))
            .L(X(x0 + w), Z(z0 - 0.05)).L(X(x0 - 0.05), Z(z0)));
        線(p => p.M(X(x0 + w / 2), Z(z0)).L(X(x0 + w / 2 - 0.03), Z(z0 + h)), 0.34);
        線(p => p.M(X(x0), Z(z0 + h / 2)).L(X(x0 + w), Z(z0 + h / 2 - 0.04)), 0.34);
    };
    田(1.9, 5.9, 2.0, 2.3);
    田(4.3, 5.85, 2.0, 2.3);
    線(p => p.M(X(1.3), Z(8.3)).L(X(6.5), Z(8.25)));
    // 田鬼大箱
    線(p => p.M(X(1.0), Z(9.5)).L(X(1.0), Z(13.4)).L(X(7.0), Z(13.35))
        .L(X(7.0), Z(9.45)).L(X(0.95), Z(9.5)));
    田(1.6, 10.1, 2.1, 2.6);
    田(4.4, 10.05, 2.1, 2.6);
    // 弓弓弓三鏈脚（各二迴）
    const 弓 = (x0) => 線(p => p.M(X(x0), Z(13.6))
        .C(X(x0 - 0.7), Z(14.2), X(x0 - 0.7), Z(15.0), X(x0 + 0.1), Z(15.2))
        .C(X(x0 + 0.8), Z(15.4), X(x0 + 0.8), Z(16.2), X(x0), Z(16.5))
        .C(X(x0 - 0.7), Z(16.8), X(x0 - 0.6), Z(17.6), X(x0 + 0.1), Z(17.8))
        .C(X(x0 + 0.4), Z(17.9), X(x0 + 0.5), Z(18.2), X(x0 + 0.4), Z(18.5)));
    弓(2.2);
    弓(4.0);
    弓(5.8);
};
